---
apiVersion: apps/v1
kind: Deployment
metadata:
  annotations: {meta.helm.sh/release-name: nudgebee-agent-prod, meta.helm.sh/release-namespace: nudgebee-agent-prod}
  creationTimestamp: '2024-03-07T15:05:59Z'
  labels: {app: nudgebee-agent-prod-runner, app.kubernetes.io/managed-by: Helm}
  name: nudgebee-agent-prod-runner
  namespace: nudgebee-agent-prod
  uid: 237f9f47-3b0e-46e4-89dd-55d2b82f55bb
spec:
  progressDeadlineSeconds: 600
  revisionHistoryLimit: 10
  selector:
    matchLabels: {app: nudgebee-agent-prod-runner}
  strategy:
    rollingUpdate: {maxSurge: 25%, maxUnavailable: 25%}
    type: RollingUpdate
  template:
    metadata:
      labels: {app: nudgebee-agent-prod-runner, robustaComponent: runner}
    spec:
      automountServiceAccountToken: true
      containers:
      - env:
        - {name: PLAYBOOKS_CONFIG_FILE_PATH, value: /etc/robusta/config/active_playbooks.yaml}
        - {name: RELEASE_NAME, value: nudgebee-agent-prod}
        - {name: PROMETHEUS_ENABLED}
        - {name: SEND_ADDITIONAL_TELEMETRY}
        - {name: LOG_LEVEL, value: INFO}
        - name: INSTALLATION_NAMESPACE
          valueFrom:
            fieldRef: {apiVersion: v1, fieldPath: metadata.namespace}
        - {name: DISABLE_HELM_MONITORING, value: 'True'}
        - {name: RUNNER_VERSION, value: 0.0.26}
        - {name: KRR_IMAGE_OVERRIDE, value: 'public.ecr.aws/p0t0i2l3/krr-public:v1.0.0'}
        - {name: WEBSOCKET_RELAY_ADDRESS, value: 'wss://relay.nudgebee.com/register'}
        envFrom:
        - secretRef: {name: nudgebee-agent-prod-runner-secret, optional: true}
        image: public.ecr.aws/p0t0i2l3/nudgebee-agent:latest
        imagePullPolicy: Always
        lifecycle:
          preStop:
            exec:
              command: [bash, -c, kill -SIGINT 1]
        name: runner
        resources:
          limits: {memory: 1Gi}
          requests: {cpu: 250m, memory: 1Gi}
        securityContext:
          allowPrivilegeEscalation: false
          capabilities: {}
          privileged: false
          readOnlyRootFilesystem: false
        terminationMessagePath: /dev/termination-log
        terminationMessagePolicy: File
        volumeMounts:
        - {mountPath: /etc/robusta/auth, name: auth-config-secret}
        - {mountPath: /etc/robusta/config, name: playbooks-config-secret}
      dnsPolicy: ClusterFirst
      restartPolicy: Always
      schedulerName: default-scheduler
      securityContext: {}
      serviceAccount: nudgebee-agent-prod-runner-service-account
      serviceAccountName: nudgebee-agent-prod-runner-service-account
      terminationGracePeriodSeconds: 30
      volumes:
      - name: playbooks-config-secret
        secret: {defaultMode: 420, optional: true, secretName: nudgebee-agent-prod-playbooks-config-secret}
      - name: auth-config-secret
        secret: {defaultMode: 420, optional: true, secretName: nudgebee-agent-prod-auth-config-secret}
